import React, { useState } from 'react';
import axios from 'axios';
import MapDisplay from './components/MapDisplay';
import SafetyIndicators from './components/SafetyIndicators';
import SOSButton from './components/SOSButton';
import './App.css';
import { MapPinIcon, MagnifyingGlassIcon } from '@heroicons/react/24/solid';

function App() {
  const [source, setSource] = useState('');
  const [destination, setDestination] = useState('');
  const [sourceCoords, setSourceCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [routeFound, setRouteFound] = useState(false);
  const [loading, setLoading] = useState(false);
  const [safeWaypoints, setSafeWaypoints] = useState([]);

  const geocode = async (place) => {
    try {
      const res = await axios.get(`https://nominatim.openstreetmap.org/search`, {
        params: { q: place, format: 'json', limit: 1 },
      });
      if (res.data.length > 0) {
        return { lat: parseFloat(res.data[0].lat), lng: parseFloat(res.data[0].lon) };
      }
    } catch (err) {
      console.error("Geocoding error:", err);
    }
    return null;
  };

  const handleFindRoute = async () => {
    if (!source.trim() || !destination.trim()) return alert('Please enter both locations');
    setLoading(true);
    setRouteFound(false);

    try {
      const src = await geocode(source);
      const dest = await geocode(destination);

      if (!src || !dest) {
        setLoading(false);
        return alert('Could not find coordinates for these locations.');
      }

      setSourceCoords(src);
      setDestinationCoords(dest);

      const response = await axios.post('http://localhost:3002/getSafeRoute', {
        source: src,
        destination: dest
      });

      const waypoints = response.data.waypoints || [src, dest];
      setSafeWaypoints(waypoints);
      setRouteFound(true);

    } catch (error) {
      console.error("Error calculating safe route:", error);
      alert("Backend routing failed. Please check if your Node.js server is running on port 3002.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="relative h-screen w-full bg-gray-100 font-sans overflow-hidden">
      
      {/* Background Map */}
      <div className="absolute inset-0 z-0">
         <MapDisplay 
            waypoints={safeWaypoints} 
            source={sourceCoords} 
            destination={destinationCoords} 
         /> 
      </div>

      {/* Floating UI Card - Compact Version for Desktop */}
      <div className="absolute top-4 left-4 sm:top-6 sm:left-6 z-10 w-[calc(100%-2rem)] sm:w-80 md:w-96">
        <div className="bg-white/90 backdrop-blur-md shadow-2xl rounded-2xl p-5 border border-white/50 transition-all duration-500">
          
          {/* Branding Section - Scaled Down */}
          <div className="flex items-center space-x-3 mb-6 p-2 bg-gradient-to-r from-purple-50/50 to-pink-50/50 rounded-xl border border-purple-100 shadow-sm">
            <div className="relative flex-shrink-0 group cursor-pointer">
              <div className="absolute -inset-0.5 bg-gradient-to-r from-purple-600 to-pink-600 rounded-full blur opacity-30 group-hover:opacity-60 transition duration-500"></div>
              
              <img 
                src={process.env.PUBLIC_URL + '/Logo.jpeg'} 
                alt="SheRoute Logo" 
                className="relative h-12 w-12 rounded-full object-cover border border-white shadow-sm bg-white p-0.5"
                onError={(e) => {
                  e.target.src = 'https://ui-avatars.com/api/?name=SR&background=a855f7&color=fff&rounded=true&bold=true&size=64';
                }}
              />
            </div>

            <div>
              <h1 className="text-xl font-bold bg-gradient-to-r from-purple-700 to-pink-600 bg-clip-text text-transparent">
                SheRoute
              </h1>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Safety Navigator</p>
            </div>
          </div>
          
          {/* Input Fields - Optimized Height */}
          <div className="space-y-4">
            <div className="relative group">
              <MapPinIcon className="absolute left-3.5 top-3 h-4 w-4 text-gray-400 group-focus-within:text-purple-500 transition-colors" />
              <input
                type="text"
                placeholder="Starting Point"
                value={source}
                onChange={(e) => setSource(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 bg-gray-50/80 border border-gray-200 rounded-xl focus:bg-white focus:ring-2 focus:ring-purple-500 focus:border-transparent outline-none transition-all text-sm font-medium text-gray-700"
              />
            </div>

            <div className="relative group">
              <MapPinIcon className="absolute left-3.5 top-3 h-4 w-4 text-pink-500" />
              <input
                type="text"
                placeholder="Destination"
                value={destination}
                onChange={(e) => setDestination(e.target.value)}
                className="w-full pl-10 pr-4 py-2.5 bg-gray-50/80 border border-gray-200 rounded-xl focus:bg-white focus:ring-2 focus:ring-pink-500 focus:border-transparent outline-none transition-all text-sm font-medium text-gray-700"
              />
            </div>

            <button
              onClick={handleFindRoute}
              disabled={loading}
              className="w-full flex items-center justify-center space-x-2 bg-gradient-to-r from-purple-600 to-pink-600 hover:from-purple-700 hover:to-pink-700 text-white font-bold py-3 px-4 rounded-xl shadow-lg hover:-translate-y-0.5 transform transition-all active:scale-95 disabled:opacity-70"
            >
              <MagnifyingGlassIcon className={`h-5 w-5 ${loading ? 'animate-spin' : ''}`} />
              <span className="text-base">{loading ? 'Searching...' : 'Find Safe Route'}</span>
            </button>
          </div>

          {/* Indicators Section */}
          {routeFound && (
            <div className="mt-5 pt-5 border-t border-gray-100 animate-in fade-in slide-in-from-top-2 duration-500">
               <SafetyIndicators />
            </div>
          )}
        </div>
      </div>

      <SOSButton />
    </div>
  );
}

export default App;
